class Solution:
    def matchReplacement(self, s, sub, mappings):
        allowed = {}
        for old, new in mappings:
            allowed.setdefault(old, set()).add(new)
        n, m = len(s), len(sub)
        for start in range(n - m + 1):
            ok = True
            for j in range(m):
                sc = s[start + j]
                pc = sub[j]
                if pc == sc or sc in allowed.get(pc, ()): 
                    continue
                ok = False
                break
            if ok:
                return True
        return False

