class Solution:
    def matchReplacement(self, s, sub, mappings):
        from collections import defaultdict
        allow = defaultdict(set)
        for old, new in mappings:
            allow[old].add(new)
        for c in sub:
            allow[c].add(c)
        n, m = len(s), len(sub)
        for i in range(n - m + 1):
            j = 0
            while j < m and s[i + j] in allow[sub[j]]:
                j += 1
            if j == m:
                return True
        return False

