var matchReplacement = function(s, sub, mappings) {
    const allow = new Map();
    const add = (k, v) => {
        if (!allow.has(k)) allow.set(k, new Set());
        allow.get(k).add(v);
    };
    for (const [old, nw] of mappings) add(old, nw);
    for (const c of sub) add(c, c);
    const n = s.length, m = sub.length;
    for (let i = 0; i + m <= n; i++) {
        let j = 0;
        while (j < m && allow.get(sub[j]) && allow.get(sub[j]).has(s[i + j])) j++;
        if (j === m) return true;
    }
    return false;
};
